// ===== Configuration =====
const config = {
  search_query: 'n8n automation tutorial',
  youtube_api_key: 'AIzaSyDiUqjjch7d0TvAGlLq61RdjrJspvGVBuM',
  gemini_api_key: 'AIzaSyA_ouLgSmDlVoTp5JylSaht7FnHxnnICG0',
  output_dir: '/data/summaries',
  sub_lang: 'en',
  max_results: 1
};

return [{ json: config }];

const response = $input.first().json;
const config = $('Config').first().json;

if (!response.items || response.items.length === 0) {
  throw new Error('No videos found for query: ' + config.search_query);
}

return response.items.map(item => ({
  json: {
    videoId: item.id.videoId,
    title: item.snippet.title,
    channelTitle: item.snippet.channelTitle,
    publishedAt: item.snippet.publishedAt,
    description: item.snippet.description,
    gemini_api_key: config.gemini_api_key,
    output_dir: config.output_dir,
    sub_lang: config.sub_lang
  }
}));

const { execSync } = require('child_process');

const videoId = $json.videoId;
const subLang = $json.sub_lang || 'en';
const url = `https://www.youtube.com/watch?v=${videoId}`;

// Clean up any previous files
try { execSync(`rm -f /tmp/yt_sub_${videoId}.*`, { encoding: 'utf-8' }); } catch(e) {}

// Download subtitles with yt-dlp
try {
  execSync(
    `yt-dlp --write-auto-sub --write-sub --sub-lang ${subLang} --skip-download --sub-format vtt -o "/tmp/yt_sub_${videoId}" "${url}"`,
    { encoding: 'utf-8', timeout: 30000 }
  );
} catch (e) {
  throw new Error('yt-dlp failed: ' + (e.stderr || e.message));
}

// Read the subtitle file
let vttContent = '';
try {
  const files = execSync(`ls /tmp/yt_sub_${videoId}.*.vtt 2>/dev/null`, { encoding: 'utf-8' }).trim();
  if (files) {
    vttContent = execSync(`cat ${files.split('\n')[0]}`, { encoding: 'utf-8' });
  }
} catch (e) {
  throw new Error('No subtitle file found for video: ' + videoId);
}

// Clean up temp files
try { execSync(`rm -f /tmp/yt_sub_${videoId}.*`, { encoding: 'utf-8' }); } catch(e) {}

if (!vttContent.trim()) {
  throw new Error('Empty subtitle content for video: ' + videoId);
}

return {
  json: {
    stdout: vttContent
  }
};

const stdout = $json.stdout || '';
const videoInfo = $('Extract Video Info').first().json;

// Clean VTT format to plain text
const lines = stdout.split('\n');
const textLines = [];
const seen = new Set();

for (const line of lines) {
  const trimmed = line.trim();
  if (!trimmed) continue;
  if (trimmed.startsWith('WEBVTT')) continue;
  if (trimmed.startsWith('Kind:')) continue;
  if (trimmed.startsWith('Language:')) continue;
  if (trimmed.startsWith('NOTE')) continue;
  if (/^\d+$/.test(trimmed)) continue;
  if (/\d{2}:\d{2}[:\.]\d{2}/.test(trimmed) && trimmed.includes('-->')) continue;

  const cleaned = trimmed.replace(/<[^>]+>/g, '').trim();
  if (!cleaned) continue;

  if (!seen.has(cleaned)) {
    seen.add(cleaned);
    textLines.push(cleaned);
  }
}

const transcript = textLines.join('\n');

if (!transcript) {
  throw new Error('No subtitles found for video: ' + videoInfo.videoId);
}

// Prepare Gemini request body
const prompt = `You are a professional content summarizer. Summarize the following YouTube video transcript into a well-structured markdown document.

Requirements:
- Start with a title (# Title)
- Add video metadata (channel, date)
- Write a brief overview (2-3 sentences)
- List key points/takeaways as bullet points
- Include important details or examples
- End with a conclusion
- Write in the same language as the transcript

Video Title: ${videoInfo.title}
Channel: ${videoInfo.channelTitle}
Published: ${videoInfo.publishedAt}

Transcript:
${transcript.substring(0, 30000)}`;

const geminiBody = {
  contents: [{ parts: [{ text: prompt }] }],
  generationConfig: { temperature: 0.3, maxOutputTokens: 4096 }
};

return {
  json: {
    transcript,
    geminiBody,
    videoId: videoInfo.videoId,
    title: videoInfo.title,
    channelTitle: videoInfo.channelTitle,
    publishedAt: videoInfo.publishedAt,
    gemini_api_key: videoInfo.gemini_api_key,
    output_dir: videoInfo.output_dir
  }
};

const response = $json;
const videoInfo = $('Clean and Prepare').first().json;

const summary = response.candidates?.[0]?.content?.parts?.[0]?.text || 'Summary generation failed.';

const markdown = summary + '\n\n---\n\n' +
  '> Source: [YouTube](https://www.youtube.com/watch?v=' + videoInfo.videoId + ')  \n' +
  '> Channel: ' + videoInfo.channelTitle + '  \n' +
  '> Generated: ' + DateTime.now().toFormat('yyyy-MM-dd HH:mm') + '\n';

const binaryData = await this.helpers.prepareBinaryData(
  Buffer.from(markdown, 'utf-8'),
  videoInfo.videoId + '.md',
  'text/markdown'
);

return {
  json: {
    videoId: videoInfo.videoId,
    title: videoInfo.title,
    output_dir: videoInfo.output_dir
  },
  binary: { data: binaryData }
};
